    'U': { char: 'ᚓ', name: 'Ur' },
    'Z': { char: 'ᚗ', name: 'Straif' },
    ' ': { char: ' ', name: 'Space' }
}

export function OghamTranslator() {
    const [text, setText] = useState("")
    const [ogham, setOgham] = useState("")
    const [isDownloading, setIsDownloading] = useState(false)
    const stoneRef = useRef<HTMLDivElement>(null)

    useEffect(() => {
        const converted = text.toUpperCase().split('').map(char => {
            return OGHAM_MAP[char]?.char || char
        }).join('')
        setOgham(converted)
    }, [text])

    const downloadInscription = async () => {
        if (!stoneRef.current) return
        
        setIsDownloading(true)
        const toastId = toast.loading("Preparing your ancient inscription...")

        try {
            // Give a small delay to ensure rendering is complete
            await new Promise(r => setTimeout(r, 100))
            
            const dataUrl = await toPng(stoneRef.current, {
                quality: 1,
                pixelRatio: 3, // High resolution for printing
                backgroundColor: 'white',
                style: {
                    margin: '0',
                    transform: 'none'
                }
            })

            const link = document.createElement('a')
            link.download = `ogham-inscription-${text.toLowerCase().replace(/\s+/g, '-') || 'untiltled'}.png`
            link.href = dataUrl
            link.click()
            
            toast.success("Inscription downloaded! Ready for printing.", { id: toastId })
        } catch (error) {
            console.error("Download failed:", error)
            toast.error("Failed to capture image. Please try again.", { id: toastId })
        } finally {
            setIsDownloading(false)
        }
    }

    // Clear inscription rendering (replaces stone)
    const renderInscription = () => {
        const chars = text.toUpperCase().trim().split('').reverse()
        return (
            <div 
                ref={stoneRef}
                className="mx-auto relative py-20 min-h-[500px] flex flex-col items-center justify-end px-24 bg-white rounded-3xl"
            >
                {/* Stem Line (Continuous line) */}
                <div className="absolute top-0 bottom-12 left-1/2 w-[3px] bg-slate-900/80 -translate-x-1/2" />
                
                {/* Characters Container */}
                <div className="relative z-10 flex flex-col gap-10 w-full mb-12">
                    {chars.map((char, i) => (
                        <div key={i} className="flex items-center justify-center h-12 relative w-full group/char">
                            {/* Ogham character - The strokes centered on the line */}
                            <div className="text-6xl font-bold text-slate-900 rotate-90 absolute left-1/2 -translate-x-1/2 flex items-center justify-center min-w-[100px]">
                                {OGHAM_MAP[char]?.char || ''}
                            </div>
                            
                            {/* Latin label (on the right) */}
                            {char !== ' ' && (
                                <div className="text-3xl font-mono font-black text-slate-400 absolute left-1/2 translate-x-12 opacity-40 group-hover/char:opacity-100 transition-opacity">
                                    {char}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
                
                {/* Footer arrowhead (V-shape at the bottom) */}
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex flex-col items-center">
                    <div className="w-10 h-10 border-b-[4px] border-l-[4px] border-slate-900/60 rotate-45 -translate-y-4" />
                </div>
                
                {chars.length === 0 && (
                    <div className="text-slate-400 italic text-lg font-bold opacity-30">
                        Awaiting inscription...
                    </div>
                )}
            </div>
        )
    }

    return (
        <div className="grid lg:grid-cols-2 gap-8">
            <div className="space-y-6">
                <Card className="white-glass-card">
                    <CardHeader className="border-b border-slate-50 bg-white/50">
                        <CardTitle className="flex items-center gap-2 text-slate-900 font-bold">
                             🖋️ Inscription Editor
                        </CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-5 p-8">
                        <Textarea 
                            placeholder="Type English text to inscribe (e.g., 'DOCKET')..." 
                            value={text}
                            onChange={(e) => setText(e.target.value)}
                            className="min-h-[160px] text-lg uppercase font-black tracking-widest border-slate-100 bg-slate-50 shadow-inner rounded-2xl resize-none focus:bg-white transition-all"
                        />
                        <div className="pt-2">
                            <Button 
                                onClick={downloadInscription} 
                                className="w-full h-14 gap-3 relative overflow-hidden group shadow-xl shadow-primary/10 rounded-2xl font-black uppercase tracking-widest text-xs"
                                variant="default"
                                disabled={!text || isDownloading}
                            >
                                {isDownloading ? (
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                ) : (
                                    <Download className="w-4 h-4 transition-transform group-hover:-translate-y-1" />
                                )}
                                {isDownloading ? "Capturing..." : "Download Inscription (PNG)"}
                            </Button>
                        </div>
                    </CardContent>
                </Card>

                <Card className="white-glass-card bg-emerald-50/50 border-emerald-100/50">
                     <CardContent className="p-8">
                        <h4 className="font-black text-emerald-800 mb-3 flex items-center gap-2 text-[10px] uppercase tracking-widest">
                             📜 The Druim Backline
                        </h4>
                        <p className="text-sm text-slate-600 font-medium leading-relaxed">
                            Ogham is read from the bottom upwards. The central line, known as the <strong className="text-emerald-900">druim</strong> (ridge), 
                            acts as the backbone of the script. Strokes are carved to the left, right, or across 
                            this line to represent different vowel and consonant sounds.
                        </p>
                    </CardContent>
                </Card>
            </div>

            <div className="space-y-6">
                 <Card className="white-glass-card h-full flex flex-col border-slate-100 overflow-hidden shadow-2xl shadow-slate-200/50">
                    <CardHeader className="flex flex-row items-center justify-between border-b border-slate-50 bg-white/50 pb-4 p-6">
                        <CardTitle className="text-slate-900 font-bold">Inscription Preview</CardTitle>
                        <div className="text-[9px] uppercase tracking-[0.25em] font-black text-primary bg-primary/10 px-4 py-1.5 rounded-full border border-primary/20">
                            Read Bottom Up
                        </div>
                    </CardHeader>
                    <CardContent className="flex-1 p-12 flex flex-col items-center justify-center relative overflow-hidden bg-white">
                        {/* Decorative subtle texture/dots for light mode */}
                        <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[radial-gradient(#000_1px,transparent_1px)] [background-size:20px_20px]" />
                        
                        <div className="relative z-10 scale-90 sm:scale-110 transition-all duration-700 ease-out">
                             {renderInscription()}
                        </div>
                    </CardContent>
                     <div className="p-8 pt-0 bg-white">
                         <ShareResult 
                            title="Ogham Inscription 🗿"
                            text={`I've created an Ogham inscription: "${text}"`}
                            className="w-full"
                        />
                    </div>
                </Card>
            </div>
        </div>
    )
}

"use client"

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { motion } from "framer-motion"
import {
    Command,
    EyeOff,
    Paintbrush,
    ShieldAlert,
    Waves
} from "lucide-react"
import { useMemo, useRef, useState } from "react"

export function SteganographyBrush() {
  const [message, setMessage] = useState("")
  const [mode, setMode] = useState<'encode' | 'decode'>('encode')
  const [brushPos, setBrushPos] = useState({ x: 0, y: 0 })
  const [isBrushing, setIsBrushing] = useState(false)
  const containerRef = useRef<HTMLDivElement>(null)

  const particles = useMemo(() => {
    return Array.from({ length: 400 }).map((_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 2 + 1,
      color: `hsl(${220 + Math.random() * 60}, 70%, ${50 + Math.random() * 20}%)`
    }))
  }, [])

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return
    const rect = containerRef.current.getBoundingClientRect()
    setBrushPos({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    })
  }

  const encodedSymbols = useMemo(() => {
    return message.split('').map((char, i) => ({
        id: i,
        char,
        x: (i % 8) * 12 + 10 + Math.random() * 5,
        y: Math.floor(i / 8) * 15 + 15 + Math.random() * 5,
    }))
  }, [message])

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-700">
      <Card className="bg-slate-950 border-slate-800 shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden">
        <CardHeader className="border-b border-slate-900 flex flex-row items-center justify-between p-8">
           <div className="space-y-1">
             <CardTitle className="text-3xl font-display text-white flex items-center gap-3">
               <ShieldAlert className="h-8 w-8 text-cyan-400" />
               Quantum Steganography
             </CardTitle>
             <CardDescription className="text-slate-500 font-medium">Hide your intent within the digital noise.</CardDescription>
           </div>
           <Tabs value={mode} onValueChange={(v) => setMode(v as 'encode' | 'decode')} className="w-[200px]">
              <TabsList className="bg-slate-900 border-slate-800">
                 <TabsTrigger value="encode" className="text-xs font-black uppercase">Obscure</TabsTrigger>
                 <TabsTrigger value="decode" className="text-xs font-black uppercase">Reveal</TabsTrigger>
              </TabsList>
           </Tabs>
        </CardHeader>

        <CardContent className="p-0">
           <div className="grid lg:grid-cols-2 min-h-[500px]">
              
              {/* Input Section */}
              <div className="p-8 lg:p-12 border-b lg:border-b-0 lg:border-r border-slate-900 space-y-8">
                 <div className="space-y-4">
                    <Label className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500">Master Sequence</Label>
                    <div className="relative group">
                       <div className="absolute inset-0 bg-cyan-500/10 blur-xl opacity-0 group-focus-within:opacity-100 transition-opacity" />
                       <Input 
                         placeholder="Enter your secret message..." 
                         className="bg-slate-900 border-slate-800 text-white h-14 rounded-2xl relative z-10 font-bold placeholder:text-slate-700 focus:ring-cyan-500/50"
                         value={message}
                         onChange={(e) => setMessage(e.target.value.slice(0, 64))}
                       />
                    </div>
                    <div className="flex justify-between items-center px-1">
                       <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest leading-none">Limit: 64 Characters</span>
                       <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest leading-none">{message.length}/64</span>
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div className="p-4 rounded-2xl bg-slate-900/50 border border-slate-800 text-center space-y-2">
                       <div className="text-[9px] font-black text-cyan-500 uppercase tracking-widest">Entropy Level</div>
                       <div className="text-2xl font-black text-white">99.8%</div>
                    </div>
                    <div className="p-4 rounded-2xl bg-slate-900/50 border border-slate-800 text-center space-y-2">
                       <div className="text-[9px] font-black text-purple-500 uppercase tracking-widest">Key Depth</div>
                       <div className="text-2xl font-black text-white">256-bit</div>
                    </div>
                 </div>

                 <div className="pt-4 space-y-4">
                    <div className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-2 border-l-2 border-cyan-500 pl-3">Instruction</div>
                    <p className="text-xs text-slate-400 leading-relaxed font-medium">
                       Your message is decomposed into microscopic light-value adjustments. To reveal the sequence, move your "Quantum Brush" across the canvas on the right.
                    </p>
                 </div>
              </div>

              {/* Canvas Section */}
              <div 
                ref={containerRef}
                onMouseMove={handleMouseMove}
                onMouseEnter={() => setIsBrushing(true)}
                onMouseLeave={() => setIsBrushing(false)}
                className="relative bg-black cursor-none overflow-hidden select-none"
              >
                 {/* Noise Particles */}
                 {particles.map((p) => (
                    <div 
                      key={p.id}
                      className="absolute rounded-full opacity-20 pointer-events-none"
                      style={{
                        left: `${p.x}%`,
                        top: `${p.y}%`,
                        width: `${p.size}px`,
                        height: `${p.size}px`,
                        background: p.color,
                        boxShadow: `0 0 4px ${p.color}`
                      }}
                    />
                 ))}

                 {/* Hidden Symbols */}
                 {encodedSymbols.map((item) => {
                    const dx = brushPos.x - (item.x * (containerRef.current?.clientWidth || 0) / 100)
                    const dy = brushPos.y - (item.y * (containerRef.current?.clientHeight || 0) / 100)
                    const distance = Math.sqrt(dx * dx + dy * dy)
                    const isRevealed = isBrushing && distance < 80

                    return (
                      <motion.div
                        key={item.id}
                        initial={false}
                        animate={{
                          opacity: isRevealed ? (mode === 'decode' ? 1 : 0.05) : (mode === 'decode' ? 0.02 : 0.1),
                          scale: isRevealed ? 1.2 : 0.9,
                          filter: isRevealed ? 'blur(0px)' : 'blur(2px)',
                          color: isRevealed ? '#22d3ee' : '#334155'
                        }}
                        className="absolute font-mono font-bold text-2xl transition-all duration-300 pointer-events-none"
                        style={{
                          left: `${item.x}%`,
                          top: `${item.y}%`,
                        }}
                      >
                         {item.char}
                      </motion.div>
                    )
                 })}

                 {/* Brush Visualizer */}
                 <motion.div 
                   animate={{
                     x: brushPos.x - 40,
                     y: brushPos.y - 40,
                     opacity: isBrushing ? 1 : 0,
                     scale: isBrushing ? 1 : 0.5
                   }}
                   transition={{ type: "spring", damping: 20, stiffness: 300, mass: 0.5 }}
                   className="absolute pointer-events-none z-50 rounded-full border border-cyan-500/30 bg-cyan-500/5 flex items-center justify-center backdrop-blur-sm"
                   style={{ width: 80, height: 80 }}
                 >
                    <div className="absolute inset-0 rounded-full border-t border-cyan-400 rotate-12 animate-spin-slow opacity-50" />
                    <Command className="h-4 w-4 text-cyan-400 opacity-40" />
                 </motion.div>

                 {/* Scanline Effect */}
                 <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_4px,3px_100%]" />
              </div>

           </div>
        </CardContent>
      </Card>

      <div className="grid md:grid-cols-3 gap-6">
         {[
           { title: "Entropy Mask", desc: "Intent is shattered across 400 unique coordinate vectors to ensure non-detection.", icon: Waves, color: "text-cyan-400" },
           { title: "Visual Synthesis", desc: "Symbols are phase-shifted to remain invisible outside the quantum focal point.", icon: EyeOff, color: "text-purple-400" },
           { title: "Quantum Brush", desc: "A localized decryption field that reconstructs light data into readable intent.", icon: Paintbrush, color: "text-emerald-400" }
         ].map((item, idx) => (
           <Card key={idx} className="bg-slate-900 border-slate-800 p-6 group hover:border-slate-700 transition-all">
              <item.icon className={`h-6 w-6 ${item.color} mb-4 transition-transform group-hover:scale-110`} />
              <h3 className="font-black text-[10px] uppercase tracking-widest text-slate-200 mb-2">{item.title}</h3>
              <p className="text-[10px] text-slate-500 leading-relaxed font-medium">{item.desc}</p>
           </Card>
         ))}
      </div>
    </div>
  )
}

"use client"

import { ShareResult } from "@/components/molecules/share-result"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Zap } from "lucide-react"
import { useEffect, useRef, useState } from "react"

type Result = { midichlorian: number, title: string, alignment: number, aspects: { control: number, sense: number, alter: number } }

export function ForceSensitivityCalculator() {
  const [step, setStep] = useState(1)
  const [lineage, setLineage] = useState("unknown")
  const [focusScore, setFocusScore] = useState(0)
  const [vision, setVision] = useState("")
  const [result, setResult] = useState<Result | null>(null)
  
  // Focus Mini-game
  const [gameState, setGameState] = useState<'idle' | 'active' | 'complete'>('idle')
  const [orbSize, setOrbSize] = useState(1)
  const [growing, setGrowing] = useState(true)
  const [clicks, setClicks] = useState(0)
  const requestRef = useRef<number | null>(null)

  useEffect(() => {
    if (gameState === 'active') {
       const animate = () => {
         setOrbSize(s => {
           if (s >= 1.5) setGrowing(false)
           if (s <= 0.5) setGrowing(true)
           return growing ? s + 0.01 : s - 0.01
         })
         requestRef.current = requestAnimationFrame(animate)
       }
       requestRef.current = requestAnimationFrame(animate)
       return () => cancelAnimationFrame(requestRef.current!)
    }
  }, [gameState, growing])

  const clickOrb = () => {
    // Target is 1.0 (mid-breath) or 1.5/0.5 (extremes)? Legacy code: >0.98 or <0.62 is perfect.
    // Let's simplify: Extremes are best (full inhale/exhale) for "Balance".
    const score = (orbSize > 1.4 || orbSize < 0.6) ? 20 : (orbSize > 1.2 || orbSize < 0.8) ? 10 : 2
    setFocusScore(s => s + score)
    setClicks(c => c + 1)
    if (clicks >= 4) setGameState('complete')
  }

  const calculate = () => {
    let base = 2500
    let algn = 50
    
    // Lineage
    if (lineage === 'skywalker') { base *= 1.8; algn = 50 }
    if (lineage === 'kenobi') { base *= 1.4; algn += 10 }
    if (lineage === 'palpatine') { base *= 1.6; algn -= 15 }
    if (lineage === 'yoda') { base *= 1.5; algn += 5 }

    // Focus
    base += focusScore * 50
    
    // Vision
    if (vision === 'search') { base *= 1.1; algn += 10 }
    if (vision === 'protect') { base *= 1.0; algn += 20 }
    if (vision === 'convince') { base *= 1.2; algn -= 10 }
    if (vision === 'break') { base *= 1.4; algn -= 25 }

    const count = Math.round(base)
    const title = count > 15000 ? "Grand Master" : count > 10000 ? "Master" : count > 7000 ? "Knight" : "Sensitive"

    setResult({
      midichlorian: count,
      title,
      alignment: Math.max(0, Math.min(100, algn)),
      aspects: { control: Math.min(100, focusScore), sense: 50, alter: 50 } // Simplified
    })
    setStep(4)
  }

  return (
    <div className="max-w-2xl mx-auto animate-in fade-in duration-700">
       <Card className="bg-slate-950 border-yellow-500/30 overflow-hidden relative">
         <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-10 pointer-events-none"></div>
         <CardHeader>
           <CardTitle className="text-3xl font-display text-yellow-400 text-center flex items-center justify-center gap-2">
             <Zap className="h-6 w-6"/> Holocron Aptitude Test
           </CardTitle>
           <CardDescription className="text-center">Trial {step} of 3</CardDescription>
         </CardHeader>
         <CardContent className="space-y-8 min-h-[400px] flex flex-col justify-center">
            
            {step === 1 && (
               <div className="space-y-6 animate-in slide-in-from-right relative z-10">
                 <h2 className="text-xl font-bold text-slate-100 text-center">Trial 1: The Calling</h2>
                 <p className="text-slate-300 text-center">From where does your connection stem?</p>
                 <div className="grid gap-3">
                   {[['unknown', 'Unknown Heritage'], ['skywalker', 'Skywalker Bloodline'], ['kenobi', 'Kenobi Lineage'], ['palpatine', 'Palpatine Heritage'], ['yoda', 'Unknown Species']].map(([val, label]) => (
                     <button key={val} onClick={() => setLineage(val)} className={`p-4 rounded border font-medium ${lineage === val ? 'bg-yellow-900/40 border-yellow-500 text-yellow-100' : 'bg-slate-800 border-slate-700 text-slate-200 hover:bg-slate-700'} transition focus:ring-2 focus:ring-yellow-500`}>
                       {label}
                     </button>
                   ))}
                 </div>
                 <Button onClick={() => setStep(2)} className="w-full bg-yellow-600 hover:bg-yellow-700 text-black font-bold">Next Trial</Button>
               </div>
            )}

            {step === 2 && (
               <div className="space-y-6 animate-in slide-in-from-right flex flex-col items-center relative z-10">
                 <h2 className="text-xl font-bold text-slate-100 text-center">Trial 2: Focus</h2>
                 <p className="text-slate-300 text-center">Click the orb when it pulses to its extremes.</p>
                 
                 <div className="relative w-48 h-48 flex items-center justify-center my-8">
                    <button 
                      onClick={clickOrb}
                      disabled={gameState === 'complete'}
                      aria-label="Focus Orb"
                      className="rounded-full bg-blue-500 shadow-[0_0_30px_#3b82f6] transition-transform duration-75 focus:ring-4 focus:ring-blue-300"
                      style={{ width: '60px', height: '60px', transform: `scale(${orbSize})` }}
                    />
                 </div>
                 
                 {gameState === 'idle' && <Button onClick={() => setGameState('active')} className="bg-blue-600 hover:bg-blue-700 text-white">Begin Meditation</Button>}
                 {gameState === 'active' && <p className="text-blue-300 animate-pulse font-bold">Focus...</p>}
                 {gameState === 'complete' && <Button onClick={() => setStep(3)} className="w-full bg-yellow-600 hover:bg-yellow-700 text-black font-bold">Trial Complete</Button>}
               </div>
            )}

            {step === 3 && (
               <div className="space-y-6 animate-in slide-in-from-right relative z-10">
                 <h2 className="text-xl font-bold text-slate-100 text-center">Trial 3: Insight</h2>
                 <p className="text-slate-300 text-center italic">"You see a locked door. Beyond it, power. The key is lost."</p>
                 <div className="grid gap-3">
                    {[
                      ['search', 'Search for the Key', 'Patience reveals path.'],
                      ['protect', 'Guard the Door', 'Some power must be kept.'],
                      ['convince', 'Persuade the Lock', 'The mind is the key.'],
                      ['break', 'Break the Wall', 'Power is to be taken.']
                    ].map(([val, label, sub]) => (
                      <button key={val} onClick={() => setVision(val)} className={`p-4 rounded border text-left ${vision === val ? 'bg-yellow-900/40 border-yellow-500 text-yellow-100' : 'bg-slate-800 border-slate-700 text-slate-200 hover:bg-slate-700'} transition focus:ring-2 focus:ring-yellow-500`}>
                        <div className="font-bold">{label}</div>
                        <div className="text-xs opacity-70 text-slate-300">{sub}</div>
                      </button>
                    ))}
                 </div>
                 <Button onClick={calculate} disabled={!vision} className="w-full bg-yellow-600 hover:bg-yellow-700 text-black font-bold">Reveal Path</Button>
               </div>
            )}

            {step === 4 && result && (
               <div className="space-y-8 animate-in zoom-in text-center">
                 <div>
                    <div className="text-sm text-yellow-500 uppercase tracking-widest mb-2">Midichlorian Count</div>
                    <div className="text-6xl font-black text-white glow-yellow">{result.midichlorian.toLocaleString()}</div>
                    <div className="text-2xl mt-2 text-yellow-200">{result.title} Potential</div>
                 </div>

                 <div className="space-y-2">
                    <div className="flex justify-between text-xs uppercase text-slate-500 font-bold px-1">
                       <span>Dark</span><span>Balance</span><span>Light</span>
                    </div>
                    <div className="h-4 bg-slate-900 rounded-full overflow-hidden border border-slate-800 relative">
                       <div className="absolute top-0 bottom-0 w-1 bg-white shadow-[0_0_10px_white]" style={{ left: result.alignment + '%' }} />
                       <div className="h-full w-full bg-gradient-to-r from-red-900 via-slate-800 to-blue-900 opacity-50"/>
                    </div>
                    <div className="text-slate-400 text-sm">{result.alignment < 40 ? "Dark Tendencies" : result.alignment > 60 ? "Light Adherent" : "Gray Alignment"}</div>
                 </div>

                 <ShareResult 
                   title="Force Sensitivity Analysis"
                   text={`I have a midichlorian count of ${result.midichlorian.toLocaleString()} and show ${result.title} potential! What's your connection?`}
                 />
                 
                 <Button onClick={() => { setStep(1); setFocusScore(0); setGameState('idle'); }} variant="ghost" className="text-slate-500 hover:text-white">Retake Trials</Button>
               </div>
            )}

         </CardContent>
       </Card>
    </div>
  )
}

