const RECIPES: Record<string, PotionResult> = {
  'moonflower_phoenixfeather': { name: 'Elixir of Rejuvenation', tier: 'Epic', desc: 'Heals wounds and restores vitality.', warn: 'Side effect: Glowing skin.' },
  'dragonscale_sunstone': { name: 'Draught of Stone Skin', tier: 'Epic', desc: 'Grants incredible physical resistance.' },
  'moonflower_shadowcap': { name: 'Potion of Invisibility', tier: 'Rare', desc: 'Renders the drinker unseen.' },
  'dragonscale_phoenixfeather': { name: 'Liquid Fire', tier: 'Dangerous', desc: 'Extremely volatile explosive.', warn: 'DO NOT DRINK.' },
  'shadowcap_voidcrystal': { name: 'Draught of Living Death', tier: 'Legendary', desc: 'Induces a death-like slumber.', warn: 'Requires antidote.' },
  'frostfern_voidcrystal': { name: 'Winter\'s Grasp', tier: 'Epic', desc: 'Control over ice and cold.' },
  'ironwood_sunstone_dragonscale': { name: 'Potion of the Colossus', tier: 'Legendary', desc: 'Vastly increases size and strength.', warn: 'Causes exhaustion.' },
}

export function PotionBrewerCalculator() {
  const [selected, setSelected] = useState<string[]>([])
  const [discovered, setDiscovered] = useState<string[]>([])
  const [brewing, setBrewing] = useState(false)
  const [lastResult, setLastResult] = useState<PotionResult | null>(null)

  const toggleIngredient = (id: string) => {
    if (selected.includes(id)) setSelected(s => s.filter(x => x !== id))
    else if (selected.length < 3) setSelected(s => [...s, id])
  }

  const brew = () => {
    setBrewing(true)
    setTimeout(() => {
      const key = selected.slice().sort().join('_')
      let res = RECIPES[key]
      
      if (!res) {
        // Procedural generation fallback
        const props: Record<ElementKey, number> = { fire: 0, life: 0, illusion: 0, chaos: 0, order: 0, death: 0 }
        selected.forEach(id => {
          const ing = INGREDIENTS.find(i => i.id === id)!
          Object.entries(ing.properties).forEach(([k, v]) => props[k] += v)
        })
        const dom = (Object.keys(props) as ElementKey[]).reduce((a, b) => props[a] > props[b] ? a : b)
        res = {
           name: `Minor ${dom.charAt(0).toUpperCase() + dom.slice(1)} Concoction`, 
           tier: 'Common', 
           desc: 'A murky mixture with weak magical properties.',
           warn: 'Tastes like burnt socks.'
        }
      } else {
        if (!discovered.includes(key)) setDiscovered(p => [...p, key])
      }

      setLastResult(res)
      setBrewing(false)
    }, 1500)
  }

  const cauldronColor = useMemo(() => {
    if (selected.length === 0) return '#4b5563'
    // Mix colors roughly logic
    return '#8b5cf6' // Generic purple magic for now, could be dynamic
  }, [selected])

  return (
    <div className="grid lg:grid-cols-12 gap-8 animate-in fade-in duration-700">
      
      {/* Shelf */}
      <Card className="lg:col-span-4 bg-slate-950 border-purple-900/50 h-fit">
        <CardHeader>
           <CardTitle className="text-purple-400 flex items-center gap-2"><FlaskConical/> Ingredients</CardTitle>
           <CardDescription>Select up to 3</CardDescription>
        </CardHeader>
        <CardContent className="grid grid-cols-2 gap-3">
           {INGREDIENTS.map(ing => (
             <button
               key={ing.id}
               onClick={() => toggleIngredient(ing.id)}
               disabled={!selected.includes(ing.id) && selected.length >= 3}
               className={`p-3 rounded-lg border text-left transition-all ${
                 selected.includes(ing.id) 
                   ? "bg-purple-900/40 border-purple-500 ring-1 ring-purple-500" 
                   : "bg-slate-900/50 border-slate-800 hover:bg-purple-900/20"
               } disabled:opacity-50 disabled:cursor-not-allowed`}
             >
               <div className="text-2xl mb-1">{ing.icon}</div>
               <div className="font-bold text-sm text-slate-200">{ing.name}</div>
             </button>
           ))}
        </CardContent>
      </Card>

      {/* Cauldron */}
      <Card className="lg:col-span-8 bg-slate-950 border-purple-900/50 relative overflow-hidden">
         <CardHeader>
           <CardTitle className="text-purple-400 flex items-center gap-2"><Sparkles/> Alchemy Station</CardTitle>
         </CardHeader>
         <CardContent className="flex flex-col items-center justify-center space-y-8 min-h-[400px]">
            
            {/* Cauldron Visual */}
            <div className="relative w-48 h-48 flex items-center justify-center">
               <div className={`absolute bottom-0 w-32 h-32 rounded-b-full bg-slate-800 border-4 border-slate-700 flex items-center justify-center overflow-hidden`}>
                  <div 
                    className={`absolute bottom-0 left-0 right-0 bg-purple-600 transition-all duration-1000 ${brewing ? 'animate-bounce' : ''}`}
                    style={{ height: selected.length * 33 + '%', opacity: 0.8 }}
                  />
                  {brewing && (
                    <div className="absolute inset-0 flex items-center justify-center">
                       <span className="animate-spin text-4xl">🌀</span>
                    </div>
                  )}
               </div>
               {/* Legs */}
               <div className="absolute bottom-[-10px] w-40 flex justify-between px-2">
                 <div className="w-4 h-8 bg-slate-800 -rotate-12 rounded"/>
                 <div className="w-4 h-8 bg-slate-800 rotate-12 rounded"/>
               </div>
            </div>

            {/* Action */}
            <div className="w-full max-w-md space-y-4">
               {lastResult && !brewing && (
                 <div className="bg-purple-950/30 p-4 rounded-xl border border-purple-500/30 text-center animate-in zoom-in">
                    <div className="text-sm uppercase tracking-widest text-purple-400 mb-1">{lastResult.tier}</div>
                    <h3 className="text-2xl font-bold text-white mb-2">{lastResult.name}</h3>
                    <p className="text-slate-300 italic mb-3">"{lastResult.desc}"</p>
                    {lastResult.warn && (
                      <div className="flex items-center justify-center gap-2 text-red-400 text-sm font-bold bg-red-950/20 p-2 rounded">
                        <AlertTriangle className="h-4 w-4"/> {lastResult.warn}
                      </div>
                    )}
                 </div>
               )}

               <Button 
                onClick={brew} 
                disabled={selected.length === 0 || brewing}
                className="w-full bg-purple-600 hover:bg-purple-700 text-lg h-12"
               >
                 {brewing ? "Brewing..." : "Mix Ingredients"}
               </Button>
            </div>

            {lastResult && !brewing && (
              <ShareResult title="Alchemy Discovery" text={`I brewed a ${lastResult.name} (${lastResult.tier}) using the Potion Brewer! 🧪`} />
            )}

         </CardContent>
      </Card>
      
      {/* Grimoire */}
      <div className="lg:col-span-12">
        <div className="flex items-center gap-2 text-lg font-bold text-slate-400 mb-4 px-2">
           <Scroll className="h-5 w-5"/> Discovered Recipes ({discovered.length}/{Object.keys(RECIPES).length})
        </div>
        <div className="grid sm:grid-cols-2 md:grid-cols-4 gap-4">
           {Object.values(RECIPES).map((r, i) => {
             const key = Object.keys(RECIPES)[i]
             const isFound = discovered.includes(key)
             return (
               <div key={key} className={`p-4 rounded border ${isFound ? 'bg-slate-900 border-purple-500/30' : 'bg-slate-950 border-slate-900 opacity-50'}`}>
                 <div className="font-bold text-slate-200">{isFound ? r.name : "???"}</div>
                 <div className="text-xs text-purple-400 uppercase">{isFound ? r.tier : "Locked"}</div>
               </div>
             )
           })}
        </div>
      </div>

    </div>
  )
}

"use client"

import { ShareResult } from "@/components/molecules/share-result"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Progress } from "@/components/ui/progress"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import {
    Bandage,
    Biohazard,
    Box,
    Brain,
    Dumbbell,
    HeartPulse,
    Leaf,
    ShieldAlert,
    Swords,
    Target,
    User,
    Users
} from "lucide-react"
import { useEffect, useState } from "react"

export function ZombieSurvivalCalculator() {
  const [fitness, setFitness] = useState<string>("2")
  const [skills, setSkills] = useState({
    melee: false,
    ranged: false,
    firstAid: false,
    foraging: false
  })
  const [groupSize, setGroupSize] = useState<string>("small")
  const [zombieType, setZombieType] = useState<string>("slow")
  const [location, setLocation] = useState<string>("suburb")
  
  const [result, setResult] = useState<null | {
    chance: number;
    profile: string;
    subScores: { combat: number; resource: number; security: number };
    strategies: string[];
    weaknesses: string[];
  }>(null)

  const calculateSurvival = () => {
    let combat = 0
    let resource = 0
    let security = 0

    // Fitness (1=Couch, 2=Average, 3=Athlete)
    const fitVal = parseInt(fitness)
    combat += fitVal * 10
    resource += fitVal * 5

    // Skills
    if (skills.melee) combat += 20
    if (skills.ranged) combat += 30
    if (skills.firstAid) resource += 20
    if (skills.foraging) resource += 15

    // Group Size
    if (groupSize === 'small') {
      security += 15
      resource += 10
      combat += 5
    } else if (groupSize === 'large') {
      security += 25
      resource -= 10 // more mouths to feed
    } else { // alone
      security -= 10
      resource += 5 // easier to stay hidden
    }

    // Zombie Type Modifiers
    const zombieMods: Record<string, number> = { slow: 1, fast: 0.7, smart: 0.5, mutated: 0.4 }
    const mod = zombieMods[zombieType]
    combat *= mod
    security *= mod

    // Location
    const locScores: Record<string, { combat: number; resource: number; security: number }> = {
      city: { combat: 5, resource: 15, security: -30 },
      suburb: { combat: 0, resource: 5, security: 0 },
      rural: { combat: -5, resource: -15, security: 25 },
      bunker: { combat: 10, resource: -25, security: 50 },
    }
    const loc = locScores[location]
    combat += loc.combat
    resource += loc.resource
    security += loc.security

    // Clamp (0-100)
    const finalCombat = Math.max(0, Math.min(100, Math.round(combat)))
    const finalResource = Math.max(0, Math.min(100, Math.round(resource)))
    const finalSecurity = Math.max(0, Math.min(100, Math.round(security)))

    // Overall Chance
    const chance = Math.round((finalCombat * 0.4) + (finalResource * 0.3) + (finalSecurity * 0.3))

    // Profile & Tips
    let profile = ""
    if (chance >= 80) profile = "Apocalypse Legend"
    else if (chance >= 65) profile = "Hardened Survivor"
    else if (chance >= 45) profile = "Scrappy Fighter"
    else if (chance >= 25) profile = "Zombie Bait"
    else profile = "First Course"

    const strategies = []
    if (finalCombat > 70) strategies.push("You are a formidable fighter. Take the lead on supply runs.")
    if (finalSecurity > 70) strategies.push("Your shelter is your greatest asset. Fortify it further.")
    if (finalResource > 60) strategies.push("Your resourcefulness is key. Focus on scavenging and first aid.")
    if (groupSize !== 'alone') strategies.push("Leverage your group's strength for defense and scouting.")
    if (zombieType === 'smart') strategies.push("The infected are intelligent. Vary your routines and avoid patterns.")

    const weaknesses = []
    if (finalCombat < 40) weaknesses.push("Your combat skills are lacking. Prioritize stealth and avoidance.")
    if (finalSecurity < 40) weaknesses.push("Your location is a deathtrap. Find a more secure shelter immediately.")
    if (finalResource < 40) weaknesses.push("You'll run out of supplies quickly. Scavenging must be a top priority.")
    if (groupSize === 'large') weaknesses.push("A large group attracts attention and consumes resources rapidly.")
    if (groupSize === 'alone' && finalCombat < 60) weaknesses.push("Being alone makes you vulnerable. Consider finding trustworthy allies.")

    if (strategies.length === 0) strategies.push("Your situation is balanced but has no clear advantage. Adaptability is your only hope.")
    if (weaknesses.length === 0) weaknesses.push("You are well-rounded, but overconfidence can be your downfall. Stay vigilant.")

    setResult({
      chance,
      profile,
      subScores: { combat: finalCombat, resource: finalResource, security: finalSecurity },
      strategies,
      weaknesses
    })
  }

  useEffect(() => {
    calculateSurvival()
  }, [fitness, skills, groupSize, zombieType, location])

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <Card className="white-glass-card shadow-xl shadow-red-500/5">
        <CardHeader className="border-b border-slate-100 bg-white/50">
          <CardTitle className="text-3xl font-display text-red-600 flex items-center gap-2">
            <Biohazard className="h-8 w-8 animate-pulse text-red-500" />
            Outbreak Analysis
          </CardTitle>
          <CardDescription className="text-slate-500 font-medium">Configure your survivor profile and calculated threat level.</CardDescription>
        </CardHeader>
        <CardContent className="grid gap-10 md:grid-cols-2 p-8">
          
          {/* Controls */}
          <div className="space-y-8">
            
