"use client"

import { ShareResult } from "@/components/molecules/share-result"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Switch } from "@/components/ui/switch"
import { Moon } from "lucide-react"
import { useMemo, useState } from "react"

export function SleepCycleCalculator() {
  const [mode, setMode] = useState<'wake' | 'sleep'>('wake') // 'wake': I want to wake up at..., 'sleep': If I sleep now...
  const [hour, setHour] = useState('7')
  const [minute, setMinute] = useState('00')
  const [ampm, setAmpm] = useState('AM')
  const [now, setNow] = useState(false) // For 'sleep' mode: sleep now vs sleep at specific time

  const calculateCycles = () => {
    let targetTime = new Date()
    
    if (mode === 'wake' || !now) {
      targetTime.setHours(
        ampm === 'PM' && hour !== '12' ? parseInt(hour) + 12 : (ampm === 'AM' && hour === '12' ? 0 : parseInt(hour))
      )
      targetTime.setMinutes(parseInt(minute))
      targetTime.setSeconds(0)
      
      // If target is in the past, assume tomorrow (for wake mode) or next occurence
      if (targetTime < new Date()) {
        targetTime.setDate(targetTime.getDate() + 1)
      }
    }

    const cycles = []
    const cycleLength = 90 // minutes
    const fallingAsleepTime = 14 // average minutes to fall asleep

    if (mode === 'wake') {
      // If I want to wake up at X, when should I sleep?
      // Count backwards 90 min cycles from wake time
      // Subtract falling asleep time
      for (let c = 6; c >= 3; c--) {
        const sleepTime = new Date(targetTime.getTime() - (c * cycleLength * 60000) - (fallingAsleepTime * 60000))
        cycles.push({
          cycles: c,
          time: sleepTime,
          label: c === 5 || c === 6 ? "Optimal" : "Sufficient"
        })
      }
    } else {
      // If I sleep at X, when should I wake up?
      // Count forwards 90 min cycles from sleep time + falling asleep
      const baseTime = now ? new Date() : targetTime
      const startSleep = new Date(baseTime.getTime() + (fallingAsleepTime * 60000))
      
      for (let c = 3; c <= 6; c++) {
        const wakeTime = new Date(startSleep.getTime() + (c * cycleLength * 60000))
        cycles.push({
          cycles: c,
          time: wakeTime,
          label: c === 5 || c === 6 ? "Optimal" : "Sufficient"
        })
      }
    }

    return cycles
  }

  const results = useMemo(calculateCycles, [mode, hour, minute, ampm, now])

  const formatTime = (date: Date) => {
    return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <Card className="bg-slate-900 border-indigo-500/30 shadow-[0_0_30px_rgba(79,70,229,0.1)]">
        <CardHeader>
          <CardTitle className="text-3xl font-display text-indigo-400 flex items-center gap-2">
            <Moon className="h-8 w-8 text-indigo-500 fill-indigo-500/20" />
            Sleep Cycle Optimizer
          </CardTitle>
          <CardDescription className="text-indigo-200/60">
            Master your REM cycles. Waking up in the middle of a sleep cycle leaves you groggy. 
            Aim for 5-6 cycles (7.5 - 9 hours).
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-8 p-8">
           
           <div className="bg-slate-950 p-6 rounded-xl border border-indigo-900/50 space-y-6">
              <div className="flex gap-4 p-1 bg-slate-900 rounded-lg w-fit mx-auto border border-slate-800">
                 <button 
                    onClick={() => setMode('wake')} 
                    className={`px-6 py-2 rounded-md font-bold text-sm transition-all ${mode === 'wake' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                 >
                    I want to wake up at...
                 </button>
                 <button 
                    onClick={() => setMode('sleep')} 
                    className={`px-6 py-2 rounded-md font-bold text-sm transition-all ${mode === 'sleep' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                 >
                    If I go to sleep at...
                 </button>
              </div>

              {mode === 'sleep' && (
                 <div className="flex justify-center items-center gap-2 text-indigo-300 font-bold">
                    <Switch checked={now} onCheckedChange={setNow} />
                    <Label>Sleep Right Now?</Label>
                 </div>
              )}

              {(!now || mode === 'wake') && (
                <div className="flex justify-center gap-2 items-center animate-in zoom-in duration-300">
                   <div className="flex items-center gap-2 bg-slate-900 px-4 py-2 rounded-lg border border-indigo-500/30">
                      <Select value={hour} onValueChange={setHour}>
                         <SelectTrigger className="w-[70px] text-2xl font-black bg-transparent border-none text-white focus:ring-0"><SelectValue/></SelectTrigger>
                         <SelectContent className="max-h-[300px]">
                            {Array.from({length: 12}, (_, i) => i + 1).map(h => (
                               <SelectItem key={h} value={h.toString()}>{h}</SelectItem>
                            ))}
                         </SelectContent>
                      </Select>
                      <span className="text-2xl font-black text-indigo-500">:</span>
                      <Select value={minute} onValueChange={setMinute}>
                         <SelectTrigger className="w-[70px] text-2xl font-black bg-transparent border-none text-white focus:ring-0"><SelectValue/></SelectTrigger>
                         <SelectContent className="max-h-[300px]">
                            {['00', '15', '30', '45'].map(m => (
                               <SelectItem key={m} value={m}>{m}</SelectItem>
                            ))}
                         </SelectContent>
                      </Select>
                      <Select value={ampm} onValueChange={setAmpm}>
                         <SelectTrigger className="w-[70px] text-xl font-bold bg-indigo-900/50 border-none text-indigo-300 focus:ring-0"><SelectValue/></SelectTrigger>
                         <SelectContent>
                            <SelectItem value="AM">AM</SelectItem>
                            <SelectItem value="PM">PM</SelectItem>
                         </SelectContent>
                      </Select>
                   </div>
                </div>
              )}
           </div>

           <div className="space-y-4">
              <h3 className="text-center text-indigo-200 font-bold text-sm uppercase tracking-widest">
                 {mode === 'wake' ? "You should try to fall asleep at one of these times:" : "You should try to wake up at one of these times:"}
              </h3>
              
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                 {results.map((r, i) => (
                    <div key={i} className={`relative p-6 rounded-xl border-2 flex flex-col items-center justify-center gap-2 transition-all hover:scale-105 ${r.cycles >= 5 ? 'bg-indigo-600 border-indigo-400 shadow-[0_0_20px_rgba(79,70,229,0.3)]' : 'bg-slate-800 border-slate-700 opacity-80'}`}>
                       {r.cycles >= 5 && (
                          <div className="absolute -top-3 px-3 py-1 bg-yellow-400 text-black text-xs font-black uppercase tracking-wider rounded-full shadow-sm">
                             Recommended
                          </div>
                       )}
                       <div className="text-3xl font-black text-white">{formatTime(r.time)}</div>
                       <div className={`text-xs font-bold uppercase ${r.cycles >= 5 ? 'text-indigo-100' : 'text-slate-400'}`}>
                          {r.cycles} Cycles ({r.cycles * 1.5} Hours)
                       </div>
                    </div>
                 ))}
              </div>
           </div>
           
           <div className="flex justify-center mt-8">
              <ShareResult 
                 title="Optimal Sleep Found" 
                 text={`I'm optimizing my sleep! Aiming for ${results[3].cycles} cycles (${results[3].cycles * 1.5} hrs) to wake up feeling fresh. 🌙`} 
              />
           </div>

        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { ShareResult } from "@/components/molecules/share-result"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Slider } from "@/components/ui/slider"
import { Infinity } from "lucide-react"
import { useEffect, useRef, useState } from "react"

export function DoublePendulum() {
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const [isPlaying, setIsPlaying] = useState(false)
  const [trailLength, setTrailLength] = useState(100)
  const [mass1, setMass1] = useState(10)
  const [mass2, setMass2] = useState(10)
  
  // Physics State
  const state = useRef({
    a1: Math.PI / 2, // angle 1
    a2: Math.PI / 2, // angle 2
    a1_v: 0, // velocity
    a2_v: 0,
    trail: [] as { x1: number, y1: number, x2: number, y2: number }[]
  })

  // Constants
  const L1 = 100
  const L2 = 100
  const G = 1

  const animate = () => {
    if (!canvasRef.current) return
    const ctx = canvasRef.current.getContext('2d')
    if (!ctx) return
    
    // Physics Calc
    const { a1, a2, a1_v, a2_v } = state.current
    const m1 = mass1
    const m2 = mass2
    
    const num1 = -G * (2 * m1 + m2) * Math.sin(a1)
    const num2 = -m2 * G * Math.sin(a1 - 2 * a2)
    const num3 = -2 * Math.sin(a1 - a2) * m2
    const num4 = a2_v * a2_v * L2 + a1_v * a1_v * L1 * Math.cos(a1 - a2)
    const den = L1 * (2 * m1 + m2 - m2 * Math.cos(2 * a1 - 2 * a2))
    const a1_a = (num1 + num2 + num3 * num4) / den

    const num5 = 2 * Math.sin(a1 - a2)
    const num6 = (a1_v * a1_v * L1 * (m1 + m2))
    const num7 = G * (m1 + m2) * Math.cos(a1)
    const num8 = a2_v * a2_v * L2 * m2 * Math.cos(a1 - a2)
    const den2 = L2 * (2 * m1 + m2 - m2 * Math.cos(2 * a1 - 2 * a2))
    const a2_a = (num5 * (num6 + num7 + num8)) / den2

    state.current.a1_v += a1_a
    state.current.a2_v += a2_a
    state.current.a1 += state.current.a1_v
    state.current.a2 += state.current.a2_v

    // Damping (optional, keeps it sane) - removing for true chaos
    // state.current.a1_v *= 0.999
    // state.current.a2_v *= 0.999

    // Positions
    const cx = canvasRef.current.width / 2
    const cy = 150
    const x1 = cx + L1 * Math.sin(state.current.a1)
    const y1 = cy + L1 * Math.cos(state.current.a1)
    const x2 = x1 + L2 * Math.sin(state.current.a2)
    const y2 = y1 + L2 * Math.cos(state.current.a2)

    // Add trail
    state.current.trail.push({ x1, y1, x2, y2 })
    if (state.current.trail.length > trailLength) {
      state.current.trail.shift()
    }

    // Draw
    ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height)
    
    // Draw Trail
    ctx.beginPath()
    state.current.trail.forEach((t, i) => {
       ctx.strokeStyle = `rgba(168, 85, 247, ${i / state.current.trail.length})` // Purple fade
       ctx.lineWidth = 2
       if (i === 0) ctx.moveTo(t.x2, t.y2)
       else ctx.lineTo(t.x2, t.y2)
    })
    ctx.stroke()

    // Draw Rods
    ctx.beginPath()
    ctx.strokeStyle = '#cbd5e1'
    ctx.lineWidth = 4
    ctx.moveTo(cx, cy)
    ctx.lineTo(x1, y1)
    ctx.lineTo(x2, y2)
    ctx.stroke()

    // Draw Pivot
    ctx.beginPath()
    ctx.fillStyle = '#94a3b8'
    ctx.arc(cx, cy, 5, 0, 2 * Math.PI)
    ctx.fill()

    // Draw Mass 1
    ctx.beginPath()
    ctx.fillStyle = '#60a5fa' // Blue
    ctx.arc(x1, y1, m1, 0, 2 * Math.PI)
    ctx.fill()

    // Draw Mass 2
    ctx.beginPath()
    ctx.fillStyle = '#a855f7' // Purple
    ctx.arc(x2, y2, m2, 0, 2 * Math.PI)
    ctx.fill()
  }

  const animationRef = useRef<number | null>(null)

  useEffect(() => {
    if (isPlaying) {
      const loop = () => {
        animate()
        animationRef.current = requestAnimationFrame(loop)
      }
      loop()
    } else {
      cancelAnimationFrame(animationRef.current!)
    }
    return () => cancelAnimationFrame(animationRef.current!)
  }, [isPlaying, trailLength, mass1, mass2])

  const reset = () => {
    state.current = {
      a1: Math.PI / 2,
      a2: Math.PI / 2,
      a1_v: 0,
      a2_v: 0,
      trail: []
    }
    // Do one render
    animate()
  }
  
  useEffect(() => { reset() }, [])

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <Card className="bg-slate-950 border-purple-900">
        <CardHeader>
          <CardTitle className="text-3xl font-display text-purple-400 flex items-center gap-2">
            <Infinity className="h-8 w-8" />
            Chaotic Double Pendulum
          </CardTitle>
          <CardDescription>A physical demonstration of chaos theory. Small changes, big consequences.</CardDescription>
        </CardHeader>
        <CardContent className="grid lg:grid-cols-12 gap-8">
           
           <div className="lg:col-span-8 bg-slate-900 rounded-xl overflow-hidden border border-slate-800 relative">
              <canvas 
                ref={canvasRef} 
                width={800} 
                height={500} 
                className="w-full h-full object-contain"
              />
              {!isPlaying && (
                <div className="absolute inset-0 flex items-center justify-center bg-black/20 backdrop-blur-[1px]">
                   <Button onClick={() => setIsPlaying(true)} className="bg-purple-600 hover:bg-purple-700 text-lg py-6 px-8 rounded-full shadow-[0_0_30px_#9333ea]">
                      Start Simulation
                   </Button>
                </div>
              )}
           </div>

           <div className="lg:col-span-4 space-y-8">
              <div className="space-y-6 bg-slate-900/50 p-6 rounded-xl border border-slate-800">
                 <div className="space-y-4">
                    <div className="flex justify-between text-sm text-slate-400">
                       <span>Tail Length</span>
                       <span>{trailLength}</span>
                    </div>
                    <Slider value={[trailLength]} onValueChange={([v]) => setTrailLength(v)} min={10} max={500} step={10} className="[&_.range-thumb]:bg-purple-500" />
                 </div>
                 
                 <div className="space-y-4">
                    <div className="flex justify-between text-sm text-slate-400">
                       <span>Mass 1 (Blue)</span>
                       <span>{mass1}kg</span>
                    </div>
                    <Slider value={[mass1]} onValueChange={([v]) => setMass1(v)} min={5} max={30} step={1} className="[&_.range-thumb]:bg-blue-500" />
                 </div>

                 <div className="space-y-4">
                    <div className="flex justify-between text-sm text-slate-400">
                       <span>Mass 2 (Purple)</span>
                       <span>{mass2}kg</span>
                    </div>
                    <Slider value={[mass2]} onValueChange={([v]) => setMass2(v)} min={5} max={30} step={1} className="[&_.range-thumb]:bg-purple-500" />
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <Button variant="outline" onClick={() => setIsPlaying(!isPlaying)} className="border-slate-700 hover:bg-slate-800 text-slate-300">
                    {isPlaying ? "Pause" : "Resume"}
                 </Button>
                 <Button variant="destructive" onClick={reset} className="bg-red-900/30 hover:bg-red-900/50 text-red-300 border border-red-900">
                    Reset Chaos
                 </Button>
              </div>

              <ShareResult 
                 title="I created Chaos" 
                 text="I'm simulating a double pendulum physics system. Seeing the butterfly effect in real-time! 🦋" 
              />
           </div>

        </CardContent>
      </Card>
    </div>
  )
}

"use client"

import { ShareResult } from "@/components/molecules/share-result"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { ArrowRightLeft } from "lucide-react"
import { useMemo, useState } from "react"

export function MinecraftPortalPlanner() {
  const [size, setSize] = useState('small')
  const [customW, setCustomW] = useState(4)
  const [customH, setCustomH] = useState(5)
  const [coordType, setCoordType] = useState<'overworld' | 'nether'>('overworld')
  const [coords, setCoords] = useState({ x: 0, y: 64, z: 0 })

  const requirements = useMemo(() => {
    let w = 4, h = 5
    if (size === 'medium') { w = 6; h = 7 }
    if (size === 'large') { w = 8; h = 9 }
    if (size === 'custom') { w = Math.max(4, customW); h = Math.max(5, customH) }

    return {
       width: w,
       height: h,
       obsidian: (w * 2) + (h * 2) - 4, // Corners optional? This formula assumes full frame with corners.
       interior: (w - 2) * (h - 2)
    }
  }, [size, customW, customH])

  const convertedCoords = useMemo(() => {
    if (coordType === 'overworld') {
       return { x: Math.floor(coords.x / 8), y: coords.y, z: Math.floor(coords.z / 8), dest: 'Nether' }
    } else {
       return { x: coords.x * 8, y: coords.y, z: coords.z * 8, dest: 'Overworld' }
    }
  }, [coords, coordType])

  return (
    <div className="space-y-8 animate-in fade-in duration-700 font-sans">
      <Card className="bg-[#121212] border-[#3C0F59] border-4 shadow-xl text-white overflow-hidden">
        <CardHeader className="bg-[#2D0A42] border-b-4 border-[#1A0526]">
           <CardTitle className="text-center font-bold text-2xl tracking-widest text-[#D685E0] uppercase flex items-center justify-center gap-3">
             <div className="w-8 h-8 bg-[#3C0F59] border-2 border-[#542478]"></div> 
             Nether Architect
           </CardTitle>
        </CardHeader>
        
        <CardContent className="p-8 grid md:grid-cols-2 gap-8">
           
           {/* Section 1: Portal Builder */}
           <div className="space-y-6">
              <h3 className="font-bold text-[#D685E0] uppercase border-b border-[#3C0F59] pb-2">Portal Configuration</h3>
              
              <div className="space-y-2">
                 <label className="text-sm font-bold text-slate-400">Frame Size</label>
                 <Select value={size} onValueChange={setSize}>
                    <SelectTrigger className="bg-[#1A1A1A] border-[#333]"><SelectValue/></SelectTrigger>
                    <SelectContent className="bg-[#1A1A1A] border-[#333] text-white">
                       <SelectItem value="small">Standard (4x5)</SelectItem>
                       <SelectItem value="medium">Medium (6x7)</SelectItem>
                       <SelectItem value="large">Large (8x9)</SelectItem>
                       <SelectItem value="custom">Custom</SelectItem>
                    </SelectContent>
                 </Select>
              </div>

              {size === 'custom' && (
                 <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <label className="text-xs text-slate-500">Width</label>
                       <input type="number" value={customW} onChange={e => setCustomW(Number(e.target.value))} className="w-full bg-[#1A1A1A] border border-[#333] p-2 rounded text-white"/>
                    </div>
                    <div className="space-y-1">
                       <label className="text-xs text-slate-500">Height</label>
                       <input type="number" value={customH} onChange={e => setCustomH(Number(e.target.value))} className="w-full bg-[#1A1A1A] border border-[#333] p-2 rounded text-white"/>
                    </div>
                 </div>
              )}
              
              <div className="bg-[#1A1A1A] p-4 rounded border border-[#333] space-y-2">
                  <div className="flex justify-between">
                     <span className="text-slate-400">Obsidian Blocks:</span>
                     <span className="font-bold text-[#D685E0]">{requirements.obsidian}</span>
                  </div>
                  <div className="flex justify-between">
                     <span className="text-slate-400">Interior Spaces:</span>
                     <span className="font-bold text-[#A020F0]">{requirements.interior}</span>
                  </div>
              </div>

              {/* Visual Preview */}
              <div className="flex justify-center items-center p-4 bg-[#0a0a0a] rounded border border-[#222] min-h-[150px]">
                  <div style={{ 
                     display: 'grid', 
                     gridTemplateColumns: `repeat(${requirements.width}, 1fr)`,
                     gap: '2px',
                     width: `${requirements.width * 12}px`
                  }}>
                     {Array.from({ length: requirements.width * requirements.height }).map((_, i) => {
                        const x = i % requirements.width;
                        const y = Math.floor(i / requirements.width);
                        const isFrame = x === 0 || x === requirements.width - 1 || y === 0 || y === requirements.height - 1;
                        return (
                          <div 
                            key={i} 
                            style={{ 
                              width: '10px', height: '10px',
                              backgroundColor: isFrame ? '#1f1f1f' : '#6A0DAD', // Obsidian vs Portal
                              boxShadow: isFrame ? 'inset 0 0 2px #000' : '0 0 4px #A020F0',
                              border: isFrame ? '1px solid #333' : 'none'
                             }} 
                          />
                        )
                     })}
                  </div>
              </div>

           </div>

           {/* Section 2: Coordinate Calculator */}
           <div className="space-y-6">
              <h3 className="font-bold text-[#D685E0] uppercase border-b border-[#3C0F59] pb-2">Coordinate Linker</h3>
              
              <div className="flex bg-[#1A1A1A] p-1 rounded">
                 <button onClick={() => setCoordType('overworld')} className={`flex-1 text-sm py-1 rounded ${coordType === 'overworld' ? 'bg-green-700 text-white' : 'text-slate-500 hover:text-white'}`}>Overworld</button>
                 <ArrowRightLeft className="w-4 h-4 mx-2 text-slate-500 self-center"/>
                 <button onClick={() => setCoordType('nether')} className={`flex-1 text-sm py-1 rounded ${coordType === 'nether' ? 'bg-red-900 text-white' : 'text-slate-500 hover:text-white'}`}>Nether</button>
              </div>

              <div className="grid grid-cols-3 gap-2">
                 <div className="space-y-1">
                    <label className="text-xs text-slate-500 font-bold uppercase">X</label>
                    <input type="number" value={coords.x} onChange={e => setCoords({...coords, x: Number(e.target.value)})} className="w-full bg-[#1A1A1A] border border-[#333] p-2 rounded text-white font-mono"/>
                 </div>
                 <div className="space-y-1">
                    <label className="text-xs text-slate-500 font-bold uppercase">Y</label>
                    <input type="number" value={coords.y} onChange={e => setCoords({...coords, y: Number(e.target.value)})} className="w-full bg-[#1A1A1A] border border-[#333] p-2 rounded text-white font-mono"/>
                 </div>
                 <div className="space-y-1">
                    <label className="text-xs text-slate-500 font-bold uppercase">Z</label>
                    <input type="number" value={coords.z} onChange={e => setCoords({...coords, z: Number(e.target.value)})} className="w-full bg-[#1A1A1A] border border-[#333] p-2 rounded text-white font-mono"/>
                 </div>
              </div>

              <div className="bg-[#2D0A42] p-6 rounded border border-[#542478] text-center space-y-2">
                 <div className="text-xs uppercase text-[#D685E0]/70 font-bold">Build in {convertedCoords.dest} at:</div>
                 <div className="text-2xl font-mono font-bold text-white tracking-widest">
                    {convertedCoords.x} / {convertedCoords.y} / {convertedCoords.z}
                 </div>
                 <div className="text-xs italic text-slate-400 mt-2">
                    (Y-coordinate doesn't strictly matter for linking, but match it for convenience!)
                 </div>
              </div>
              
              <ShareResult 
                 title="Portal Plans"
                 text={`Planning a ${requirements.width}x${requirements.height} Nether Portal. Needs ${requirements.obsidian} obsidian. Linking local coords to ${convertedCoords.x}, ${convertedCoords.y}, ${convertedCoords.z}!`}
              />

           </div>

        </CardContent>
      </Card>
    </div>
  )
}
